<style>
	/* comment spacing in a raw at-rule prelude is preserved verbatim (matches prettier);
	the single-space, no-space, and extra-space forms are each dual-stable */
	@keyframes anim1 /* c */ {
		0% {
			transform: translateX(0);
		}
	}
	@keyframes anim2/* c */ {
		0% {
			opacity: 0;
		}
	}
	@keyframes anim3  /* c */ {
		0% {
			opacity: 1;
		}
	}
</style>
